function possibleRoots(edges, guesses, k) {
    let n = edges.length + 1;
    let in_degree = Array(n).fill(0);
    let guess_parents = new Set();

    for (let guess of guesses) {
        guess_parents.add(guess[0]);
    }

    for (let edge of edges) {
        in_degree[edge[1]]++;
    }

    let possible_roots = 0;
    for (let i = 0; i < n; ++i) {
        if (in_degree[i] === 0) {
            if (k === 0 || guess_parents.has(i)) {
                possible_roots++;
            }
        } else if (in_degree[i] === 1 && guesses.length - k < in_degree[i]) {
            possible_roots++;
        }
    }
    return possible_roots;
}
```

    1. Create a new array `in_degree` of length `n` with all values initialized to 0.
2. Create a set `guess_parents` to store all the parents as guessed by Bob.
3. Iterate through the guesses and add the parent nodes to `guess_parents`.
4. Iterate through the edges and increase the in-degree count of each child node.
5. Iterate from 0 to n-1 and check for each node `i`,
    - If the in-degree of the node is 0 (possible root), increment the counter of possible roots if k is 0 or i is present in `guess_parents`.
    - If the in-degree of the node is 1, increment the counter of possible roots if the number of guesses left `guesses.size() - k` is less than the in-degree of the node.
6. Return the possible roots count.

