import java.util.Set;
import java.util.HashSet;
import java.util.List;

public int possibleRoots(List<List<Integer>> edges, List<List<Integer>> guesses, int k) {
    int n = edges.size() + 1;
    int[] in_degree = new int[n];
    Set<Integer> guess_parents = new HashSet<>();

    for (List<Integer> guess : guesses) {
        guess_parents.add(guess.get(0));
    }

    for (List<Integer> edge : edges) {
        in_degree[edge.get(1)]++;
    }

    int possible_roots = 0;
    for (int i = 0; i < n; ++i) {
        if (in_degree[i] == 0) {
            if (k == 0 || guess_parents.contains(i)) {
                possible_roots++;
            }
        } else if (in_degree[i] == 1 && guesses.size() - k < in_degree[i]) {
            possible_roots++;
        }
    }
    return possible_roots;
}
```

